mapper.update:
/** CmmtBannerDao.update */
update cmmt_banner set
	 banner_id                 = #{bannerId}
	,banner_nm                 = #{bannerNm}
	,system_id                 = #{systemId}
	,banner_type               = #{bannerType}
	,begin_dt                  = #{beginDt}
	,end_dt                    = #{endDt}
	,target_url                = #{targetUrl}
	,new_window                = #{newWindow}
	,animation                 = #{animation}
	,text_html                 = #{textHtml}
	,pc_image_file_id          = #{pcImageFileId}
	,mobile_image_file_id      = #{mobileImageFileId}
	,image_alt_cn              = #{imageAltCn}
	,sort_order                = #{sortOrder}
	,enabled                   = #{enabled}
	,creator_id                = #{creatorId}
	,created_dt                = #{createdDt}
	,updater_id                = #{updaterId}
	,updated_dt                = #{updatedDt}
where
	banner_id = #{bannerId}

mapper.delete:
/** CmmtBannerDao.delete */
delete from
	cmmt_banner
