	banner_id = #{bannerId}

mapper.select:
/** CmmtBannerDao.selectList */ select
,#{totalItems} + 1 - (row_number() over(order by created_dt desc)) as rn from cmmt_banner where
order by created_dt desc offset #{beginRowNum} - 1 limit #{itemsPerPage}
